AreaEventManager = {}

AreaEventManager.curAreaEvent = nil --当前地图事件
AreaEventManager.lastAreaEventTime = 0 --上次地图事件时间
AreaEventManager.isCountDown = false --是否在倒计时

local AreaEventMap =
{
    [Define.AreaEventType.Wrestling] = WrestlingAreaEvent
}

local function createAreaEvent(config)
    local class = AreaEventMap[config.eventType]
    if class == nil then
        return nil
    end
    local event = class.new(config)
    return event
end

function AreaEventManager:init()
    self.isNoticeAll = false --是否通知过了
end

function AreaEventManager:onTick(ticks)
    if ticks % GameMatch.tickPerSecond ~= 0 then
        return
    end

    if not self.curAreaEvent then
        AreaEventManager:startCountDown()
    else
        AreaEventManager:onTickAreaEvent(ticks)
    end
end

function AreaEventManager:onTickAreaEvent(ticks)
    if self.curAreaEvent:isEnd() then
        self:endAreaEvent()
    else
        self.curAreaEvent:onTick(ticks)
    end
end

function AreaEventManager:startCountDown()
    --判断开启人数
    if not AreaEventManager.isCountDown and PlayerManager:getPlayerCount() < GameConfig.eventOpenNeedPlayerNum then
        self:endAreaEvent()
        return
    end

    if os.time() - self.lastAreaEventTime >= GameConfig.AreaEventInterval then
        self:startAreaEvent()
        AreaEventManager.isCountDown = false
    else
        if not self.isNoticeAll then
            --通知下一次事件开始
            self:noticeAllNextAreaEvent(GameConfig.AreaEventInterval)
        end
        AreaEventManager.isCountDown = true
    end
end

function AreaEventManager:startAreaEvent()
    local config = AreaEventConfig:randomAreaEvent()
    if config == nil then
        return
    end

    self.curAreaEvent = createAreaEvent(config)
    self.curAreaEvent:onStart()
    --print(string.format("self.curAreaEvent:onStart() %d %d %d %d",
    --        self.curAreaEvent.eventId, self.curAreaEvent.startTime, os.time(), self.curAreaEvent:getLiveTime()))
    self:noticeAllAreaEvent()

    self.isNoticeAll = false
end

function AreaEventManager:endAreaEvent()
    self.lastAreaEventTime = os.time()
    if self.curAreaEvent then
        self.curAreaEvent:onEnd()
        self.curAreaEvent = nil
    end
end

function AreaEventManager:noticeNextAreaEvent(player, time)
    local params =
    {
        AreaEventInterval = time
    }
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData(player.rakssid, "noticeNextAreaEvent", data)
end

function AreaEventManager:noticeAllNextAreaEvent(time)
    self.isNoticeAll = true
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        self:noticeNextAreaEvent(player, time)
    end
end

--通知玩家地图事件开始
function AreaEventManager:noticeAllAreaEvent()
    --print("AreaEventManager:noticeAllAreaEvent")
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        self:checkPlayerPosition(player, player:getPosition())
        self:noticeAreaEvent(player)
    end
end

function AreaEventManager:noticeAreaEvent(player)
    if not self.curAreaEvent or player:isAdvancing() then
        return
    end

    local passTime = self.curAreaEvent.config.eventTime - self.curAreaEvent:getLiveTime()
    local params =
    {
        eventId = self.curAreaEvent.eventId,
        noticeMessage = self.curAreaEvent.config.noticeMessage,
        eventTime = passTime,
        needMuscle = self.curAreaEvent.config.needMuscle,
        rewardType = self.curAreaEvent.config.rewardType,
        rewardNum = self.curAreaEvent.config.rewardNum,
        strAreaTeleportPos = self.curAreaEvent.config.strAreaTeleportPos,
    }
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData(player.rakssid, "noticeAreaEvent", data)
    --print("AreaEventManager:noticeAreaEvent " .. inspect.inspect(params))
end

function AreaEventManager:doTeleportArea(player, eventId)
    if self.curAreaEvent == nil then
        return
    end

    if self.curAreaEvent.eventId ~= eventId then
        return
    end

    if player.property.muscleMass < self.curAreaEvent.config.needMuscle or player:isAdvancing() then
        return
    end

    if player:isBeGrab() then
        return
    end

    if player:isGrab() then
        player:unbindAllEntity()
    end

    --local pos = VectorUtil.newVector3(self.curAreaEvent.config.areaTeleportPos[1],
    --        self.curAreaEvent.config.areaTeleportPos[2], self.curAreaEvent.config.areaTeleportPos[3])
    player:teleportPos(self.curAreaEvent:randomPos(), true)
end

function AreaEventManager:checkPlayerPosition(player, position)
    if player == nil or self.curAreaEvent == nil then
        return
    end

    local config = self.curAreaEvent.config
    if not config then
        return
    end

    local posInRect = MathUtil:checkPosInRect(position, Rect.new(
            config.areaRange[1].x,
            config.areaRange[1].y,
            config.areaRange[2].x,
            config.areaRange[2].y))

    if posInRect then
        self.curAreaEvent:enterArea(player)
    else
        self.curAreaEvent:leaveArea(player)
    end

    self:checkPullBack(player, position, config)
end

function AreaEventManager:checkPullBack(player, position, config)
    local needPullBack = (player.property.muscleMass < self.curAreaEvent.config.needMuscle or player:isAdvancing()) --是否需要拉回
    if needPullBack == false then
        return
    end

    local posInRect = MathUtil:checkPosInRect(position, Rect.new(
            config.areaRange[1].x - GameConfig.areaExpand,
            config.areaRange[1].y - GameConfig.areaExpand,
            config.areaRange[2].x + GameConfig.areaExpand,
            config.areaRange[2].y + GameConfig.areaExpand))

    if needPullBack and posInRect then
        --local pos = VectorUtil.newVector3(config.enterPos[1], config.enterPos[2], config.enterPos[3])
        player:teleportPos(player:randomInitPos())
    end
end

return AreaEventManager